2. 它是其父亲节点的右孩子，则从其父亲开始往上追溯到第一个向右的节点，如果没有这个节点或者说没有父亲节点，则无下一个节点，若有则取之

```python
def nextNode(node):
    def leftest(node):
        while node.lc:
            node = node.lc
        return node
    if node.rc:
        return leftest(node.rc)
    if not node.parent:
        return None
    if node == node.parent.lc:
        return node.parent
    elif node == node.parent.rc:
        while node.parent.parent:
            if node.parent != node.parent.parent.lc:
                node = node.parent
            else:
                return node.parent.parent
        return None
```

## Queue Implementation

### Queue using Linked List
```python
class ListNode(object):
    def __init__(self, x):
        self.val = x
        self.next = None

class Queue(object):
    def __init__(self):
        self.head = None
        self.tail = None
        self.size = 0

    def __str__(self):
        '''print Queue'''
        res = ''
        cur = self.head
        while cur:
            res += str(cur.val)
            res += ' '
            cur = cur.next
        return res

    def push(self, val):
        node = ListNode(val)
        if not self.head:
            self.head = self.tail = node
        else:
            self.tail.next = node
            self.tail = node
        self.size += 1

    def popleft(self):
        if not self.head:
            return None
        pop_val = self.head.val
        self.head = self.head.next
        if self.head == None:
            self.tail = None
        self.size -= 1
        return pop_val

    def peekleft(self):
        if self.head:
            return self.head.val
        return None

    def get_size(self):
        return self.size

    def is_empty(self):
        return self.size == 0
```

## Stack Implementation

### Stack using Linked List
```python
class ListNode(object):
    def __init__(self, x):
        self.val = x
        self.next = None

class Stack(object):
    def __init__(self):
        self.head = None
        self.size = 0

    def push(self, val):
        new_node = ListNode(val)
        new_node.next = self.head
        self.head = new_node
        self.size += 1

    def pop(self):
        if self.head == None:
            return None
        pop_val = self.head.val
        self.head = self.head.next
        self.size -= 1
        return pop_val

    def peek(self):
        return self.head.val

    def get_size(self):
        return self.size

    def is_empty(self):
        return self.size == 0
```

