	byte[] bb = new byte[4];
	bb[3] = (byte) (x >> 24);
	bb[2] = (byte) (x >> 16);
	bb[1] = (byte) (x >> 8);
	bb[0] = (byte) (x >> 0);
	return bb;
}

//byte数组转换为int类型
public static int byteArrayToInt(byte[] bb) {
	return (int) ((((bb[3] & 0xff) << 24) | ((bb[2] & 0xff) << 16) | ((bb[1] & 0xff) << 8) | ((bb[0] & 0xff) << 0)));
}
