  /*对于任一结点cur：
  1)访问结点cur，并将结点cur入栈;
  2)判断结点cur的左孩子是否为空，若为空，则取栈顶结点并进行出栈操作，并将栈顶结点的右孩子置为当前的结点cur，循环至1);
      若不为空，则将cur的左孩子置为当前的结点cur;
  3)直到cur为NULL并且栈为空，则遍历结束。*/
  void NonRecursive::PreTraverse(BinaryTree *T) {
  	stack s;
  	BinaryTree *cur=T;
  	while (cur!=nullptr||!s.empty()) {
